const userPrompt = $.input.prompt || '';

let prompt = 'You are a content safety classifier. Evaluate the following image generation prompt for safety.

';
prompt += 'PROMPT: ' + userPrompt + '

';
prompt += 'Classify this prompt:
';
prompt += '- Is it safe for image generation?
';
prompt += '- Does it contain violent, explicit, or harmful content?
';
prompt += '- Rate the safety level

';
prompt += 'Then if safe, enhance the prompt for better image generation results.

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "isSafe": true,
';
prompt += '  "safetyLevel": "safe|caution|unsafe",
';
prompt += '  "reason": "why safe or unsafe",
';
prompt += '  "enhancedPrompt": "improved prompt for image generation",
';
prompt += '  "negativePrompt": "things to avoid in generation",
';
prompt += '  "suggestedDimensions": "1024x1024",
';
prompt += '  "styleNotes": "style-specific tips"
';
prompt += '}';
return { prompt };

let raw = $.steps.aiSafety.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { isSafe: true, safetyLevel: 'safe', reason: '', enhancedPrompt: $.input.prompt, negativePrompt: '', suggestedDimensions: '1024x1024', styleNotes: '' }; }

const safety = $.steps.parseSafety.output;
const style = $.input.style || 'photorealistic';

if (!safety.isSafe || safety.safetyLevel === 'unsafe') {
  return {
    subject: 'Image Generation - Content Safety Alert',
    body: 'The image prompt was flagged as unsafe.\n\nOriginal prompt: ' + $.input.prompt + '\nReason: ' + (safety.reason || 'Content policy violation') + '\n\nPlease revise the prompt and try again.',
    blocked: true
  };
}

let body = 'IMAGE GENERATION BRIEF\n';
body += '=====================\n\n';
body += 'Original Prompt: ' + $.input.prompt + '\n\n';
body += 'Enhanced Prompt: ' + (safety.enhancedPrompt || $.input.prompt) + '\n\n';
body += 'Style: ' + style + '\n';
body += 'Dimensions: ' + (safety.suggestedDimensions || '1024x1024') + '\n';
if (safety.negativePrompt) body += 'Negative Prompt: ' + safety.negativePrompt + '\n';
if (safety.styleNotes) body += 'Style Notes: ' + safety.styleNotes + '\n';
body += '\nSafety Level: ' + safety.safetyLevel + '\n';
body += '\nYou can use this enhanced prompt with any image generation service (DALL-E, Midjourney, Stable Diffusion, fal.ai).\n';

return {
  subject: 'Image Brief: ' + $.input.prompt.slice(0, 50),
  body: body,
  blocked: false
};

const safety = $.steps.parseSafety.output;
const brief = $.steps.buildCreativeBrief.output;
const blocks = [];

if (brief.blocked) {
  blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Image Generation Blocked', emoji: true } });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':no_entry: Prompt was flagged as unsafe\n*Reason:* ' + (safety.reason || 'Content policy') } });
} else {
  blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Image Brief Generated', emoji: true } });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Prompt:* ' + $.input.prompt } });
  blocks.push({ type: 'section', fields: [
    { type: 'mrkdwn', text: '*Style:*\n' + ($.input.style || 'photorealistic') },
    { type: 'mrkdwn', text: '*Safety:*\n' + (safety.safetyLevel || 'safe') }
  ] });
  if (safety.enhancedPrompt) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Enhanced:* ' + safety.enhancedPrompt.slice(0, 1000) } });
  }
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Sent to ' + $.input.recipientEmail + ' | Powered by Claude AI' }] });
const fallbackText = brief.blocked ? 'Image generation blocked' : 'Image brief: ' + $.input.prompt.slice(0, 80);
return { blocks, fallbackText };
